def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        if item < 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity if capacity != 0 else np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        if item == 0:
            priorities[i] = 0
            continue
        score = 0.0
        complexity = 1.0
        composite_penalty = 0.0
        decay = 1.0
        adjustment = 1.0
        if ratio > 4:
            for a in range(1, 5):
                temp = 0
                for b in range(1, a*3):
                    temp += ((-1)**b) * (ratio ** (b/2)) / (b + a)
                composite_penalty += temp / (a**2 + 1)
            for c in range(1, 4):
                decay *= (1 - 1 / ((ratio ** 0.5) + c**1.5))
            score = (ratio ** 4.8) / 3 + composite_penalty * 2
            if item > capacity * 5:
                adjustment = 4
            elif item > capacity * 3:
                adjustment = 3
            else:
                adjustment = 2
            priorities[i] = score * decay * adjustment
        elif 3 < ratio <= 4:
            for x in range(1, 10):
                sign = (-1) ** (x)
                score += sign * (np.sin(ratio * x) ** 2) / (x + ratio)
            for y in range(1, 7):
                decay *= (1 - (np.log1p(ratio + y) / (y + 2)))
            priorities[i] = abs(score) * decay * 15 + ratio * 2
        elif 2 < ratio <= 3:
            temp = 0
            for p in range(1, 15):
                if p % 3 == 0:
                    temp += (ratio ** p) / (p * 7)
                elif p % 2 == 0:
                    temp -= (ratio ** p) / (p * 5)
                else:
                    temp += (ratio ** (p/2)) / (p * 4)
            multiplier = 20 if ratio < 2.5 else 12
            score = abs(temp) * multiplier
            extra = 0
            for m in range(1, 8):
                extra += (np.exp(-m / ratio)) / (m + 1)
            score += extra * 5
            priorities[i] = score
        elif 1 < ratio <= 2:
            temp_score = 0
            for p in range(1, 20):
                if p % 5 == 0:
                    temp_score += (ratio ** p) / (p * 8)
                elif p % 4 == 0:
                    temp_score -= (ratio ** p) / (p * 6)
                else:
                    temp_score += ((-1) ** p) * (ratio ** (p/1.5)) / (p * 5)
            multiplier = 30 if ratio < 1.3 else 18 if ratio < 1.7 else 12
            score = abs(temp_score) * multiplier
            extras = 0
            for n in range(1, 10):
                extras += (ratio ** n) / (n ** 1.5 + 2)
            score += extras * 3
            priorities[i] = score
        elif 0 < ratio <= 1:
            temp_score = 0
            for p in range(1, 25):
                if p % 6 == 0:
                    temp_score += (ratio ** p) / (p * 4)
                elif p % 3 == 0:
                    temp_score -= (ratio ** p) / (p * 7)
                else:
                    temp_score += ((-1) ** p) * (ratio ** (p / 2)) / (p * 5)
            if ratio < 0.15:
                multiplier = 40
            elif ratio < 0.35:
                multiplier = 28
            elif ratio < 0.55:
                multiplier = 18
            elif ratio < 0.75:
                multiplier = 10
            else:
                multiplier = 7
            score = abs(temp_score) * multiplier
            penalty = 0
            for n in range(1, 12):
                penalty += (np.log1p(ratio ** n)) / (n + 2)
            score += penalty * 4
            priorities[i] = score
        else:
            priorities[i] = np.inf
        if priorities[i] != np.inf and capacity > 0:
            factor = 1.0
            for z in range(1, 6):
                factor *= (1 + (z ** 1.1) / (capacity + z))
            if ratio > 1:
                adjustment = 1 + 0.1 * np.sin(ratio * 3)
                priorities[i] *= factor * adjustment
            else:
                adjustment = 1 + 0.05 * np.cos(ratio * 7)
                priorities[i] *= factor * adjustment
        elif capacity <= 0:
            priorities[i] = np.inf
    return priorities
